import{c as e,a7 as t,y as i,B as r}from"./chunks/framework.3cjvm90C.js";const f=JSON.parse('{"title":"COMA：反事实多智能体策略梯度","description":"介绍 COMA 算法如何利用反事实基线解决多智能体信用分配问题","frontmatter":{"title":"COMA：反事实多智能体策略梯度","description":"介绍 COMA 算法如何利用反事实基线解决多智能体信用分配问题"},"headers":[],"relativePath":"rlwiki/papers/coma.md","filePath":"rlwiki/papers/coma.md","lastUpdated":1782448598000}'),n={name:"rlwiki/papers/coma.md"};function c(l,a,o,s,d,p){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="coma-counterfactual-multi-agent-policy-gradients" tabindex="-1">COMA： Counterfactual Multi-Agent Policy Gradients <a class="header-anchor" href="#coma-counterfactual-multi-agent-policy-gradients" aria-label="Permalink to “COMA： Counterfactual Multi-Agent Policy Gradients”">​</a></h1><p>论文链接：<a href="https://arxiv.org/pdf/1705.08926.pdf" target="_blank" rel="noreferrer">Counterfactual Multi-Agent Policy Gradients, AAAI 2017</a></p><p>代码链接：<a href="https://github.com/oxwhirl/pymarl" target="_blank" rel="noreferrer">github 链接</a></p><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to “问题”">​</a></h2><p>文章针对 multi-agent 设置下存在的三个挑战进行了算法设计：</p><ul><li>Modelling other agents ’ information：在 multi-agent 的设置下，过去常用的 independent actor-critic 等模型，往往会由于独立训练，导致信息共享不足，无法做到较好的 coordinated，从而效果不佳。</li><li>Multi-agent credit assignment：常规的 actor-critic 方法由于每个 actor 训练的 reward 都是基于全局的 reward，所以很难评估每个 agent 采取的 action 实际对全局的 reward 影响有多大，故而导致优化存在困难。</li><li>Curse of dimensionality in action space：由于系统是 mulit-agent，在要求算法有更好效果的情况下，往往需要求得不同 agent 采取 action 的联合概率分布，故而也导致了动作空间规模指数上升的问题。</li></ul><h2 id="解法" tabindex="-1">解法 <a class="header-anchor" href="#解法" aria-label="Permalink to “解法”">​</a></h2><p>VDN 和 QMIX 都采用了这样一种结构：中心化计算系统的$Q$函数，单智能体的$Q_{i}$函数去中心化。这种结构使得策略在训练的时候可以利用全局信息，同时每个智能体仍然只接受局部信息作为输入。类似的，在 Actor-Critic 框架中，我们同样可以通过分散 Actor，中心化 Critic 来达到同样的效果， COMA 就采用了这样的思想。此外， COMA 还考虑了另外一个问题：如何合理的分配全局系统奖励（credit assignment）。每个智能体对全局奖励的贡献是不同的，在更新 Actor 网络时，应该考虑到这种不同，分配合理的奖励给不同的 Actor。</p><h3 id="centralised-critic" tabindex="-1">Centralised critic <a class="header-anchor" href="#centralised-critic" aria-label="Permalink to “Centralised critic”">​</a></h3><p>Centralised critic，也就是集中训练一个 critic 作为全局的 critic，下图是它的具体结构：</p><p><img src="https://s1.ax1x.com/2020/08/13/dS2hEq.png" alt="dS2hEq.png"></p><p>Critic 仅仅在 learning 过程中使用，它可以基于所有 joint action 和 state information 进行训练。当 global state $S_{t}$存在的时候，直接利用它进行训练，否则使用 joint action-observation history $u_{t}, o_{t}$进行训练。而对于 actor，它在 learning 和 execution 的时候都需要，它的训练仅仅依靠来自自己的 action-observation history。</p><p>在这种设置下的 critic 能够得到来自全局的信息，而在 actor-critic 框架中，往往会利用 critic 来指导每个 agent 的学习，将全局的信息传输到每个 agent，从而提高每个 agent 对其他 agent 的信息的建模能力。</p><h3 id="counterfactual-baseline" tabindex="-1">Counterfactual baseline <a class="header-anchor" href="#counterfactual-baseline" aria-label="Permalink to “Counterfactual baseline”">​</a></h3><p>作为一个 critic，它的核心功能是辅助 policy gradient 训练，我们可以通过两种方式使用它：</p><h4 id="naive-actor-critic" tabindex="-1">Naive actor-critic <a class="header-anchor" href="#naive-actor-critic" aria-label="Permalink to “Naive actor-critic”">​</a></h4><p>最简单的方式，就是和原始的 actor-critic 一样，直接利用它估计 TD-error，并用于计算梯度。</p><p>$$ g=\\nabla_{\\theta \\pi} \\log \\pi\\left(u | \\tau_{t}^{a}\\right)\\left(r+\\gamma V\\left(s_{t+1}\\right)-V\\left(s_{t}\\right)\\right) $$</p><p>这样做的方法是无法解决 credit assignment 的问题： TD-error 考虑的是 global reward 的影响，故而对于每个 actor 而言，难以显式确认它对于 global reward 贡献，从而导致优化方向不正确。</p><h4 id="difference-reward" tabindex="-1">Difference Reward <a class="header-anchor" href="#difference-reward" aria-label="Permalink to “Difference Reward”">​</a></h4><p>它核心思想的 Per-agent shaped reward 的定义如下：</p><p>$$ D^{a}=r(s, \\mathbf{u})-r\\left(s,\\left(\\mathbf{u}^{-a}, c^{a}\\right)\\right) $$</p><p>其中，$c^{a}$是人为指定的默认 action。我们将其他 agent 的 action 固定，只研究当前 agent 的 action 变化的影响。这个 Difference reward，顾名思义也就是对 reward 作 difference，而 difference 的对象分别是当前 agent 选择的 action 的 reward 和当前 agent 被人为指定的 action 的 reward。从而得到当前 agent 选择的 action 相对默认 action 的优势。那么如果 agent 选择了能够提高$D$的 action，那么这个 action 对 global reward 也是有贡献的，这样也就部分解决了 credit assignment 的问题。</p><p>然而这种方法存在如下两个局限：</p><ul><li>需要额外的 simulation 估计$r\\left(s,\\left(\\mathbf{u}^{-a}, c^{a}\\right)\\right)$。</li><li>需要用户对每个 agent 都指定一个默认的动作$c^{a}$</li></ul><h4 id="counterfactual-baseline-1" tabindex="-1">Counterfactual baseline <a class="header-anchor" href="#counterfactual-baseline-1" aria-label="Permalink to “Counterfactual baseline”">​</a></h4><p>为了解决以上两个问题，本文引入了 counterfactual baseline。counterfactual 部分表示它继承了 difference reward 的思想，这体现了对 credit assignment 的解决方向， baseline 则体现了它在 policy gradient 中的作用。</p><p>$$ A^{a}(s, \\mathbf{u})=Q(s, \\mathbf{u})-\\sum_{y^{\\prime} a} \\pi^{a}\\left(u^{\\prime a} | \\tau^{a}\\right) Q\\left(s,\\left(\\mathbf{u}^{-a}, u^{\\prime a}\\right)\\right) $$</p><p>这个函数计算的是，固定其他智能体的动作时，一个智能体的某个动作的 Q 值与所有动作 Q 值平均值间的差。这里$a$表示某个智能体,$u$表示所有智能体的动作，$u^{−a}$表示除了$a$之外的所有智能体的动作。</p><p>方程中的第一项是当前选择的 action 的 global q-value，这表明在 centrailsed critic 中估计的是 Q 值。方程中的第二项，表征在 agent $a$的所有可能选择状态下能够获得的 global q-value 的期望，也就是常规理解的 baselines。两者做差也正是体现了当前 agent 选择的 agent 相对平均结果的优势。</p><p>这样做可以解决 2.2.2 中的两个问题：</p><ul><li>使用 centralised critic 替代了原式中的 reward，这个 critic 是直接从数据中学习的，从而避免了对 reward 的多余 simulations。</li><li>对于当前 agent 的所有动作求期望，用来衡量是否有所提升，避免了人工设计 action 的问题。</li></ul><h3 id="efficient-critic-representation" tabindex="-1">Efficient critic representation <a class="header-anchor" href="#efficient-critic-representation" aria-label="Permalink to “Efficient critic representation”">​</a></h3><p>考虑到 counterfactual baseline 的实际实现，存在维度诅咒的问题：它需要所有的 joint action 的 Q-value，如果使用神经网络，假设 agent 的 action 数量是$U$，一共有$n$个 agent，那么就需要$|U|^{n}$个输出节点，计算消耗太大。</p><p>为了简化计算， Critic 不会计算所有智能体动作组合的 Q 值（输出维度是$|U|^{n}$个），而是针对每一个智能体，将其他智能体的动作结合其他历史信息当作输入，输出该智能体每个动作对应的$Q$值（输出维度降为$|U|$）。</p><p>算法流程如下：</p><p><img src="https://s1.ax1x.com/2020/08/13/dS2Wbn.png" alt="dS2Wbn.png"></p><p>算法流程如下：</p><p><img src="https://s1.ax1x.com/2020/08/13/dS24U0.png" alt="dS24U0.png"></p><h2 id="实验内容" tabindex="-1">实验内容 <a class="header-anchor" href="#实验内容" aria-label="Permalink to “实验内容”">​</a></h2><p>在星际环境上做实验，效果好于 Independent Actor Critic 等方式。</p><h2 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to “缺点”">​</a></h2><ul><li>论文的方法未对比一些其他集中训练分步执行的算法，对比的 baselines 都比较弱；</li></ul><h2 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to “优点”">​</a></h2><ul><li>引入反事实推理的概念非常具有创新性，且给出了方法理论上的证明；</li><li>感觉确实是从问题本身出发，一步步解决各种上到顶层算法设计下到降低算法复杂度的各种方法</li></ul>',45)])])}const u=e(n,[["render",c]]);export{f as __pageData,u as default};
